#!/usr/bin/env python3
import json, os, sys

query = (sys.argv[1] if len(sys.argv) > 1 else "").strip()

wf_data = os.getenv("alfred_workflow_data") or os.getcwd()
os.makedirs(wf_data, exist_ok=True)
conf = os.path.join(wf_data, "favorites.json")

items = []

try:
    with open(conf, "r", encoding="utf-8") as f:
        favs = json.load(f)
except Exception as e:
    print(json.dumps({"items": [{
        "title": "favorites.json が読めません",
        "subtitle": f"{conf} | {e}",
        "valid": False
    }]}, ensure_ascii=False))
    raise SystemExit

def hit(x, s):
    if not s:
        return True
    s = s.lower()
    blob = " ".join([x.get("id",""), x.get("name",""), x.get("path",""), x.get("keywords","")]).lower()
    return s in blob

for x in favs:
    if not hit(x, query):
        continue
    items.append({
        "title": x.get("name", x.get("id","(no id)")),
        "subtitle": x.get("path",""),
        "arg": x.get("path","")
    })

print(json.dumps({"items": items}, ensure_ascii=False))
